package ru.memearena.battle.application; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional; import ru.memearena.battle.api.*; import ru.memearena.meme.domain.Meme; import ru.memearena.meme.infrastructure.MemeRepository; import ru.memearena.user.application.UserProfileService; import ru.memearena.vote.domain.Vote; import java.util.*; @Service public class BattleService { private final MemeRepository memes; private final UserProfileService users; private final Random random=new Random(); public BattleService(MemeRepository memes,UserProfileService users){this.memes=memes;this.users=users;} @Transactional(readOnly=true) public Optional<NextBattleResponse> next(UUID userId){users.get(userId); Optional<Meme> left=memes.findRandomLeft(userId); if(left.isEmpty()) return Optional.empty(); Optional<Meme> right=memes.findRandomRight(userId,left.get().getId()); if(right.isEmpty()) return Optional.empty(); Meme a=left.get(), b=right.get(); if(random.nextBoolean()){Meme t=a; a=b; b=t;} String battleId=Base64.getUrlEncoder().withoutPadding().encodeToString(Vote.pairKey(a.getId(),b.getId()).getBytes()); return Optional.of(new NextBattleResponse(battleId,new BattleMemeResponse(a.getId(),a.getTitle(),a.getImageUrl(),a.getRating()),new BattleMemeResponse(b.getId(),b.getTitle(),b.getImageUrl(),b.getRating()))); } }
